package com.oneil.wellness.walkplanner.data;
import com.fasterxml.jackson.databind.ObjectMapper;import com.oneil.wellness.walkplanner.activity.*;import com.oneil.wellness.walkplanner.goal.*;import com.oneil.wellness.walkplanner.history.*;import java.nio.charset.StandardCharsets;import java.time.*;import java.util.*;import org.springframework.stereotype.Service;
@Service public class HistoryExportService{
 private final WalkActivityRepository activities;private final HistoryRepository history;private final WellnessGoalService goals;private final HistoryRetentionService retention;private final ObjectMapper json=new ObjectMapper().findAndRegisterModules();
 public HistoryExportService(WalkActivityRepository a,HistoryRepository h,WellnessGoalService g,HistoryRetentionService r){activities=a;history=h;goals=g;retention=r;}
 public byte[] activitiesCsv(){StringBuilder b=new StringBuilder("id,recommendationHistoryId,status,source,opportunityStart,opportunityEnd,actualStart,actualEnd,durationMinutes,perceivedQuality,notes\n");activities.findAllByOrderByOpportunityStartDesc().forEach(v->row(b,v.getId(),v.getRecommendationHistoryId(),v.getActivityStatus(),v.getSource(),v.getOpportunityStart(),v.getOpportunityEnd(),v.getActualStart(),v.getActualEnd(),v.getDurationMinutes(),v.getPerceivedQuality(),v.getNotes()));return bytes(b);}
 public byte[] recommendationsCsv(){StringBuilder b=new StringBuilder("id,capturedAt,score,recommendedStart,recommendedEnd,calendarAvailable,providerSources,reasonSummary\n");history.findAllByOrderByCapturedAtAsc().forEach(v->row(b,v.getId(),v.getCapturedAt(),v.getScore(),v.getRecommendedStart(),v.getRecommendedEnd(),v.isCalendarAvailable(),v.getProviderSources(),v.getReasonSummary()));return bytes(b);}
 public byte[] dailyCsv(){StringBuilder b=new StringBuilder("date,completedWalks,walkingMinutes,averageDuration\n");activities.findAllByOrderByOpportunityStartDesc().stream().filter(v->v.getActivityStatus()==ActivityStatus.COMPLETED||v.getActivityStatus()==ActivityStatus.PARTIALLY_COMPLETED).collect(java.util.stream.Collectors.groupingBy(v->v.getOpportunityStart().toLocalDate())).entrySet().stream().sorted(Map.Entry.comparingByKey()).forEach(e->{int minutes=e.getValue().stream().map(WalkActivity::getDurationMinutes).filter(Objects::nonNull).mapToInt(Integer::intValue).sum();row(b,e.getKey(),e.getValue().size(),minutes,Math.round(minutes*10.0/e.getValue().size())/10.0);});return bytes(b);}
 public byte[] allJson(String timezone){try{return json.writerWithDefaultPrettyPrinter().writeValueAsBytes(Map.of("schemaVersion","2.6","exportedAt",Instant.now(),"timezone",timezone==null?"UTC":timezone,"activities",activities.findAllByOrderByOpportunityStartDesc(),"recommendations",history.findAllByOrderByCapturedAtAsc().stream().map(RecommendationHistory::snapshot).toList(),"wellnessGoals",goals.current(),"retention",retention.current()));}catch(Exception e){throw new IllegalStateException("History export could not be created.",e);}}
 private void row(StringBuilder b,Object... values){for(int i=0;i<values.length;i++){if(i>0)b.append(',');String s=values[i]==null?"":String.valueOf(values[i]);b.append('"').append(s.replace("\"","\"\"")).append('"');}b.append('\n');}private byte[] bytes(StringBuilder b){return b.toString().getBytes(StandardCharsets.UTF_8);}
}
